const events = $input.all().map(i => i.json);
const workspaceItem = $('Split By Workspace').item.json;

const MEETING_PATTERNS = [
  { type: 'standup', keywords: ['standup', 'stand-up', 'stand up', 'daily scrum', 'daily sync'] },
  { type: 'retrospective', keywords: ['retro', 'retrospective', 'sprint retro', 'team retro'] },
  { type: 'sprint_planning', keywords: ['sprint planning', 'planning poker', 'story pointing', 'backlog refinement', 'grooming'] },
  { type: 'sprint_review', keywords: ['sprint review', 'demo', 'showcase', 'sprint demo'] }
];

function classifyEvent(title) {
  const lower = (title || '').toLowerCase();
  for (const { type, keywords } of MEETING_PATTERNS) {
    if (keywords.some(k => lower.includes(k))) return type;
  }
  return 'other';
}

const classified = events
  .filter(e => e.start && (e.start.dateTime || e.start.date))
  .map(e => {
    const startTime = e.start.dateTime || `${e.start.date}T09:00:00Z`;
    const endTime = e.end?.dateTime || `${e.end?.date}T10:00:00Z`;
    const durationMs = new Date(endTime) - new Date(startTime);
    const durationMins = Math.max(0, Math.floor(durationMs / 60000));

    return {
      event_id: e.id,
      title: e.summary || 'Untitled Meeting',
      meeting_type: classifyEvent(e.summary),
      start_time: startTime,
      end_time: endTime,
      attendee_count: (e.attendees || []).length,
      is_recurring: !!(e.recurringEventId),
      duration_minutes: durationMins
    };
  });

return [{
  json: {
    workspace_id: workspaceItem.id,
    events: classified,
    synced_at: new Date().toISOString()
  }
}];

